// scrollama.min.js

(function(window, document, undefined) {
    function Scrollama(options) {
        this.options = {
            step: '.step',
            offset: 0.5,
            progress: false,
            debug: false
        };

        // 合并默认选项和用户提供的选项
        Object.assign(this.options, options);

        this.init();
    }

    Scrollama.prototype.init = function() {
        this.setupElements();
        this.setupEvents();
    };

    Scrollama.prototype.setupElements = function() {
        this.steps = document.querySelectorAll(this.options.step);
        this.container = document.querySelector('body');
    };

    Scrollama.prototype.setupEvents = function() {
        window.addEventListener('scroll', this.check.bind(this), { passive: true });
        window.addEventListener('resize', this.check.bind(this), { passive: true });
    };

    Scrollama.prototype.check = function() {
        this.steps.forEach(step => {
            const rect = step.getBoundingClientRect();
            const progress = rect.top / window.innerHeight;

            if (progress <= this.options.offset && rect.bottom >= 0) {
                this.triggerStepEnter(step);
            } else {
                this.triggerStepExit(step);
            }
        });
    };

    Scrollama.prototype.triggerStepEnter = function(step) {
        this.options.onStepEnter && this.options.onStepEnter(step);
    };

    Scrollama.prototype.triggerStepExit = function(step) {
        this.options.onStepExit && this.options.onStepExit(step);
    };

    window.scrollama = function(options) {
        return new Scrollama(options);
    };
})(window, document);
